import { useEffect, useState } from "react";
import Navbar from "./components/Navbar";
import Sidebar from "./components/Sidebar";
import AppRoutes from "./routes/AppRoutes";
import { getAuth } from "./utils/auth";
import { initializeTheme } from "./utils/theme";

export default function App() {
  const [auth, setAuthState] = useState(getAuth());
  const [sidebarOpen, setSidebarOpen] = useState(false);

  useEffect(() => {
    // Initialize theme on app load
    initializeTheme();

    const refresh = () => setAuthState(getAuth());
    window.addEventListener("auth-change", refresh);
    window.addEventListener("storage", refresh);

    return () => {
      window.removeEventListener("auth-change", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const isAdmin = auth?.role === "admin" || auth?.role === "manager" || auth?.role === "staff";

  return (
    <>
      {isAdmin ? (
        // Admin/Manager/Staff layout with sidebar
        <div className="appShell">
          <Sidebar isOpen={sidebarOpen} onClose={() => setSidebarOpen(false)} />
          <div className="appMain">
            {/* Hamburger Menu for Mobile */}
            <div style={{ padding: '12px 20px', borderBottom: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: '12px', backgroundColor: 'var(--bg)' }}>
              <span style={{ fontSize: '14px', fontWeight: '500', color: 'var(--text-light)' }}>Menu</span>
            </div>
            <div className="appContent">
              <AppRoutes />
            </div>
          </div>
        </div>
      ) : (
        // Public user layout with navbar
        <>
          <Navbar />
          <AppRoutes />
        </>
      )}
    </>
  );
}
